uniform vec4  blankout;
uniform float solidEdgeEnable;
uniform vec4  solidEdgeColor;
uniform vec2 projectorArray;
uniform vec2 projectorRes;

uniform samplerBuffer perSideControl;

// per screen controls
uniform samplerBuffer gammaCorrection;
uniform samplerBuffer blendPower;
uniform samplerBuffer luminanceControl;
uniform samplerBuffer cornerCoord;

// per edge controls
uniform samplerBuffer gammaCorrections;
uniform samplerBuffer blendPowers;
uniform samplerBuffer luminanceControls;

uniform samplerBuffer screenOverlap;
uniform samplerBuffer screenBlankout;

vec3 rgb2hsv(vec3 c)
{
	vec4 K = vec4(0.0, -1.0 / 3.0, 2.0 / 3.0, -1.0);
	vec4 p = mix(vec4(c.bg, K.wz), vec4(c.gb, K.xy), step(c.b, c.g));
	vec4 q = mix(vec4(p.xyw, c.r), vec4(c.r, p.yzx), step(p.x, c.r));

	float d = q.x - min(q.w, q.y);
	float e = 1.0e-10;
	return vec3(abs(q.z + (q.w - q.y) / (6.0 * d + e)), d / (q.x + e), q.x);
}

vec3 hsv2rgb(vec3 c)
{
	vec4 K = vec4(1.0, 2.0 / 3.0, 1.0 / 3.0, 3.0);
	vec3 p = abs(fract(c.xxx + K.xyz) * 6.0 - K.www);
	return c.z * mix(K.xxx, clamp(p - K.xxx, 0.0, 1.0), c.y);
}

vec4 perProjectorOffset(vec2 currProjector, vec4 outputRes, vec2 xy, vec2 projXY)
{
	vec2 proTexOffset;

	float firstXOffset = 0.0;
	float otherXOffset = 0.0;
	float blankXOffset = 0.0;
	float firstYOffset = 0.0;
	float otherYOffset = 0.0;
	float blankYOffset = 0.0;

	vec2 leftBlankUV = vec2(0.0);
	vec2 leftBlendUV = vec2(0.0);
	vec2 rightBlankUV = vec2(0.0);
	vec2 rightBlendUV = vec2(0.0);
	vec2 topBlankUV = vec2(0.0);
	vec2 topBlendUV = vec2(0.0);
	vec2 bottomBlankUV = vec2(0.0);
	vec2 bottomBlendUV = vec2(0.0);

	float perSide = 0.0;
	vec2 projScale = vec2(1.0/projectorRes.x,1.0/projectorRes.y);

	vec4 projectorOverlap = vec4(0.0);
	vec4 projBlankout = vec4(0.0);
	vec2 projBlankoutUnit = vec2(0.0);

	for (int i=0;i<projectorArray.x;i++){

		int realProj = i + int(currProjector.y * projectorArray.x);
		perSide = texelFetch(perSideControl,int(realProj)).r;

		if(perSide > 0.5){
			// get corner coordinates
			int projOffset = int(realProj*8);
			leftBlendUV = texelFetch(cornerCoord,projOffset+1).rg * outputRes.x;
			rightBlendUV = texelFetch(cornerCoord,projOffset+3).rg * outputRes.x;
			projectorOverlap.rg = mix(vec2(leftBlendUV.x,rightBlendUV.x),vec2(leftBlendUV.y,rightBlendUV.y),vec2(projXY.y));
		}
		else{
			projectorOverlap = texelFetch(screenOverlap,realProj) * vec4(vec2(outputRes.x),vec2(outputRes.y));
 		}

		firstXOffset += (i<projectorArray.x-1) ? projectorOverlap.g * 0.5 : 0.0;
	}


	for (int j=0;j<=currProjector.x;j++){
		int realProj = j + int(currProjector.y * projectorArray.x);
		perSide = texelFetch(perSideControl,int(realProj)).r;

		if(perSide > 0.5){
			// get corner coordinates
			int projOffset = int(realProj*8);
			leftBlendUV = texelFetch(cornerCoord,projOffset+1).rg * outputRes.x;
			rightBlendUV = texelFetch(cornerCoord,projOffset+3).rg * outputRes.x;
			projectorOverlap.rg = mix(vec2(leftBlendUV.x,rightBlendUV.x),vec2(leftBlendUV.y,rightBlendUV.y),vec2(projXY.y));

			leftBlankUV = texelFetch(cornerCoord,projOffset).rg * outputRes.x;
			rightBlankUV = texelFetch(cornerCoord,projOffset+2).rg * outputRes.x;
			projBlankoutUnit = mix(vec2(leftBlankUV.x,rightBlankUV.x),vec2(leftBlankUV.y,rightBlankUV.y),vec2(projXY.y));
		}
		else{
			projectorOverlap = texelFetch(screenOverlap,realProj) * vec4(vec2(outputRes.x),vec2(outputRes.y));
			projBlankout = texelFetch(screenBlankout,realProj);
	 		projBlankoutUnit = projBlankout.xy * outputRes.x;
 		}

		otherXOffset += projectorOverlap.r;
		blankXOffset += (j!=currProjector.x) ? - projBlankoutUnit.y - projBlankoutUnit.x : -projBlankoutUnit.x ;
	}
	otherXOffset = firstXOffset - otherXOffset;

	for (int i=0;i<projectorArray.y;i++){
		int realProj = int(currProjector.x) + int(projectorArray.x) * i;
		perSide = texelFetch(perSideControl,int(realProj)).r;

		if(perSide > 0.5){
			// get corner coordinates
			int projOffset = int(realProj*8);
			topBlendUV = texelFetch(cornerCoord,projOffset+5).rg * outputRes.y;
			bottomBlendUV = texelFetch(cornerCoord,projOffset+7).rg * outputRes.y;
			projectorOverlap.ba = mix(vec2(bottomBlendUV.x,topBlendUV.x),vec2(bottomBlendUV.y,topBlendUV.y),vec2(projXY.x));
		}
		else{	
			projectorOverlap = texelFetch(screenOverlap,realProj) * vec4(vec2(outputRes.x),vec2(outputRes.y));
		}

		firstYOffset += (i<projectorArray.y-1) ? projectorOverlap.a * 0.5 : 0.0;
	}

	for (int j=0;j<=currProjector.y;j++){
		int realProj = int(currProjector.x) + int(projectorArray.x) * j;
		perSide = texelFetch(perSideControl,int(realProj)).r;

		if(perSide > 0.5){
			// get corner coordinates
			int projOffset = int(realProj*8);
			topBlendUV = texelFetch(cornerCoord,projOffset+5).rg * outputRes.y;
			bottomBlendUV = texelFetch(cornerCoord,projOffset+7).rg * outputRes.y;
			projectorOverlap.ba = mix(vec2(bottomBlendUV.x,topBlendUV.x),vec2(bottomBlendUV.y,topBlendUV.y),vec2(projXY.x));

			topBlankUV = texelFetch(cornerCoord,projOffset+4).rg * outputRes.y;
			bottomBlankUV = texelFetch(cornerCoord,projOffset+6).rg * outputRes.y;
			projBlankoutUnit = mix(vec2(bottomBlankUV.x,topBlankUV.x),vec2(bottomBlankUV.y,topBlankUV.y),vec2(projXY.x));
		}
		else{
			projectorOverlap = texelFetch(screenOverlap,realProj) * vec4(vec2(outputRes.x),vec2(outputRes.y));
			projBlankout = texelFetch(screenBlankout,realProj);
	 		projBlankoutUnit = projBlankout.zw * outputRes.y;
		}


		otherYOffset += projectorOverlap.b;
		blankYOffset += (j<projectorArray.y-1) ? - projBlankoutUnit.y - projBlankoutUnit.x : -projBlankoutUnit.x;

	}
	otherYOffset = firstYOffset - otherYOffset;

	proTexOffset.x = (currProjector.x < 1.0) ? firstXOffset : otherXOffset + blankXOffset;
	proTexOffset.y = (currProjector.y < 1.0) ? firstYOffset : otherYOffset - blankYOffset;

	return texture(sTD2DInputs[1], xy + proTexOffset);
}

vec4 drawSmoothEdge(float loc, float extend, float blePow, float lumCon, vec3 gamma)
{
	vec4 edge;
	float curve;

	curve = loc / extend;
	curve = (curve < 0.5) ? 
		lumCon * pow(2.0 * curve, blePow) 
		: 
		1.0 - (1.0 - lumCon) * pow(2.0 * (1.0 - curve), blePow);

	edge = vec4(pow(curve, 1.0 / gamma.r), 
				pow(curve, 1.0 / gamma.g),
				pow(curve, 1.0 / gamma.b),
				1.0);

	return edge;
}

vec4 drawSmoothEdges(in vec4 overlapUnit, in vec4 projBlankout, in vec2 projXY, in float projNr, in vec4 image, in vec4 corners)
{

	float width = 1.0;
	float height = 1.0;

	vec4 blank = vec4(0.0,0.0,0.0,0.0);

	float perSide = texelFetch(perSideControl,int(projNr)).r;

	float blnPwr = texelFetch(blendPower,int(projNr)).r;
	float blnPwrL = blnPwr;
	float blnPwrR = blnPwr;
	float blnPwrT = blnPwr;
	float blnPwrB = blnPwr;

	float slc = texelFetch(luminanceControl,int(projNr)).r;
	float slcL = slc;
	float slcR = slc;
	float slcT = slc;
	float slcB = slc;

	vec3  gamma = texelFetch(gammaCorrection,int(projNr)).rgb;
	vec3  gammaL = gamma;
	vec3  gammaR = gamma;
	vec3  gammaT = gamma;
	vec3  gammaB = gamma;

	int intL = int(projNr)*4;
	int intR = 1 + int(projNr)*4;
	int intT = 2 + int(projNr)*4;
	int intB = 3 + int(projNr)*4;

	vec4 sebImage = vec4(0.0);
	if (projBlankout.x + overlapUnit.x > projXY.x){
		if (projBlankout.x > projXY.x){
			// leftBlankout
			sebImage = blank;
		}
		else if (projBlankout.z + overlapUnit.z > projXY.y){
			if (projBlankout.z > projXY.y){
				// leftBottomBlankout
				sebImage = blank;
			}
			else{
				// leftBottomBlend
				if (perSide > 0.5){
					blnPwrL = texelFetch(blendPowers,intL).r;
					blnPwrB = texelFetch(blendPowers,intB).r;

					slcL = texelFetch(luminanceControls,intL).r;
					slcB = texelFetch(luminanceControls,intB).r;

					gammaL = texelFetch(gammaCorrections,intL).rgb;
					gammaB = texelFetch(gammaCorrections,intB).rgb;
				}
				sebImage = image * 
						   drawSmoothEdge(projXY.x - projBlankout.x, overlapUnit.x, blnPwrL, slcL, gammaL) * 
						   drawSmoothEdge(projXY.y - projBlankout.z, overlapUnit.z, blnPwrB, slcB, gammaB) *
						   corners.x;
			}
		}
		else if (height - projBlankout.w - overlapUnit.w < projXY.y){
			if (height - projBlankout.w < projXY.y){
				// leftTopBlankout
				sebImage = blank;
			}
			else{
				// leftTopBlend
				if (perSide > 0.5){
					blnPwrL = texelFetch(blendPowers,intL).r;
					blnPwrT = texelFetch(blendPowers,intT).r;

					slcL = texelFetch(luminanceControls,intL).r;
					slcT = texelFetch(luminanceControls,intT).r;

					gammaL = texelFetch(gammaCorrections,intL).rgb;
					gammaT = texelFetch(gammaCorrections,intT).rgb;
				}
				sebImage = image *
						   drawSmoothEdge(projXY.x - projBlankout.x, overlapUnit.x, blnPwrL, slcL, gammaL) * 
						   drawSmoothEdge(height - projBlankout.w - projXY.y, overlapUnit.w, blnPwrT, slcT, gammaT) *
						   corners.z;
			}
		}
		else{
			// leftBlend
			if (perSide > 0.5){
				blnPwrL = texelFetch(blendPowers,intL).r;

				slcL = texelFetch(luminanceControls,intL).r;

				gammaL = texelFetch(gammaCorrections,intL).rgb;
			}
			sebImage = image *
					   drawSmoothEdge(projXY.x - projBlankout.x, overlapUnit.x, blnPwrL, slcL, gammaL);
		}
	}
	else if (width - projBlankout.y - overlapUnit.y < projXY.x){
		if (width - projBlankout.y < projXY.x){
			// rightBlankout
			sebImage = blank;
		}
		else if (projBlankout.z + overlapUnit.z > projXY.y){
			if (projBlankout.z > projXY.y){
				// rightBottomBlankout
				sebImage = blank;
			}
			else{
				// rightBottomBlend
				if (perSide > 0.5){
					blnPwrR = texelFetch(blendPowers,intR).r;
					blnPwrB = texelFetch(blendPowers,intB).r;

					slcR = texelFetch(luminanceControls,intR).r;
					slcB = texelFetch(luminanceControls,intB).r;

					gammaR = texelFetch(gammaCorrections,intR).rgb;
					gammaB = texelFetch(gammaCorrections,intB).rgb;
				}
				sebImage = image *
						   drawSmoothEdge(width - projBlankout.y - projXY.x, overlapUnit.y, blnPwrR, slcR, gammaR) *
						   drawSmoothEdge(projXY.y - projBlankout.z, overlapUnit.z, blnPwrB, slcB, gammaB) * 
						   corners.y;
			}
		}
		else if (height - projBlankout.w - overlapUnit.w < projXY.y){
			if (height - projBlankout.w < projXY.y){
				// rightTopBlankout
				sebImage = blank;
			}
			else{
				// rightTopBlend
				if (perSide > 0.5){
					blnPwrR = texelFetch(blendPowers,intR).r;
					blnPwrT = texelFetch(blendPowers,intT).r;

					slcR = texelFetch(luminanceControls,intR).r;
					slcT = texelFetch(luminanceControls,intT).r;

					gammaR = texelFetch(gammaCorrections,intR).rgb;
					gammaT = texelFetch(gammaCorrections,intT).rgb;
				}
				sebImage = image *
						   drawSmoothEdge(width - projBlankout.y - projXY.x, overlapUnit.y, blnPwrR, slcR, gammaR) * 
						   drawSmoothEdge(height - projBlankout.w - projXY.y, overlapUnit.w, blnPwrT, slcT, gammaT) * 
						   corners.w;
			}
		}
		else{
			// rightBlend
			if (perSide > 0.5){
				blnPwrR = texelFetch(blendPowers,intR).r;

				slcR = texelFetch(luminanceControls,intR).r;

				gammaR = texelFetch(gammaCorrections,intR).rgb;
			}
			sebImage = image *
					   drawSmoothEdge(width - projBlankout.y - projXY.x, overlapUnit.y, blnPwrR, slcR, gammaR);
		}
	}
	else if (projBlankout.z + overlapUnit.z > projXY.y){
		if (projBlankout.z > projXY.y){
			// bottomBlankout
			sebImage = blank;
		}
		else{
			// bottomBlend
			if (perSide > 0.5){
				blnPwrB = texelFetch(blendPowers,intB).r;

				slcB = texelFetch(luminanceControls,intB).r;

				gammaB = texelFetch(gammaCorrections,intB).rgb;
			}
			sebImage = image *
					   drawSmoothEdge(projXY.y - projBlankout.z, overlapUnit.z, blnPwrB, slcB, gammaB);
		}
	}
	else if (height - projBlankout.w - overlapUnit.w < projXY.y){
		if (height - projBlankout.w < projXY.y){
			// topBlankout
			sebImage = blank;
		}
		else{
			// topBlend
			if (perSide > 0.5){
				blnPwrT = texelFetch(blendPowers,intT).r;

				slcT = texelFetch(luminanceControls,intT).r;

				gammaT = texelFetch(gammaCorrections,intT).rgb;
			}
			sebImage = image *
					   drawSmoothEdge(height - projBlankout.w - projXY.y, overlapUnit.w, blnPwrT, slcT, gammaT);
		}
	}
	else{
		sebImage = image;
	}


	return sebImage;
}

vec4 drawSolidEdges(vec4 overlapUnit, vec4 projBlankout, vec4 solidEdgeColor, vec2 projXY, vec4 image)
{	
	float width = 1.0;
	float height = 1.0;

	//calc test pos
	vec4 blank = vec4(0.0,0.0,0.0,0.0);

	vec4 edgeImage =
			(projBlankout.x + overlapUnit.x > projXY.x) ?
				(projBlankout.x > projXY.x) ?
					blank				//leftBlankout
				:	(projBlankout.z + overlapUnit.z > projXY.y) ?
						(projBlankout.z > projXY.y) ?
							blank			//leftBottomBlankout
						: 	solidEdgeColor			//leftBottomColor
					: 	(height - projBlankout.w - overlapUnit.w < projXY.y) ?
							(height - projBlankout.w < projXY.y) ?
								blank 		//leftTop
							: 	solidEdgeColor 		//leftTopColor
						:	solidEdgeColor			//leftColor
			:	(width - projBlankout.y - overlapUnit.y < projXY.x) ?
					(width - projBlankout.y < projXY.x) ?
						blank				//rightBlankout
					:	(projBlankout.z + overlapUnit.z > projXY.y) ?
							(projBlankout.z > projXY.y) ?
								blank 		//rightBottomBlankout
							: 	solidEdgeColor		//rightBottomColor
						:	(height - projBlankout.w - overlapUnit.w < projXY.y) ?
								(height - projBlankout.w < projXY.y) ? 
									blank 	//rightTopBlankout
								:	solidEdgeColor 	//rightToColor
							:	solidEdgeColor 		//rightColor
				:	(projBlankout.z + overlapUnit.z > projXY.y) ?
						(projBlankout.z > projXY.y) ? 
							blank 			//BottomBlankout
						: 	solidEdgeColor			//BottomColor
					:	(height - projBlankout.w - overlapUnit.w < projXY.y) ?
							(height - projBlankout.w < projXY.y) ? 
								blank 		//TopBlankout
							:	solidEdgeColor		//TopColor
						:	image;
	return edgeImage;
}

out vec4 fragColor;
void main()
{
	vec2 xy = vUV.st;
	vec2 projXY = mod(xy * projectorArray,1.0);

	vec4 outputRes = uTD2DInfos[0].res;
	vec2 currProjector = floor(outputRes.zw / projectorRes * xy);
	float projNr = currProjector.x + (currProjector.y * projectorArray.x);

	float perSide = texelFetch(perSideControl,int(projNr)).r;


	vec4 projBlankout = vec4(0.0);
	vec4 overlap = vec4(0.0);
	vec4 overlapUnit = vec4(0.0);

	if(perSide < 0.5){

		// get blankout
	 	projBlankout = texelFetch(screenBlankout,int(projNr));
	 	projBlankout = vec4(projBlankout.xy * 1/projectorRes.x, projBlankout.zw * 1/projectorRes.y);

	 	// calculate overlap
	 	overlap = texelFetch(screenOverlap,int(projNr));
		overlapUnit = vec4(overlap.xy * 1/projectorRes.x , overlap.zw * 1/projectorRes.y);
		overlapUnit.x = (currProjector.x > 0.0) ? overlapUnit.x : 0.0;
		overlapUnit.y = (currProjector.x < projectorArray.x-1) ? overlapUnit.y : 0.0;
		overlapUnit.z = (currProjector.y > 0.0) ? overlapUnit.z : 0.0;
		overlapUnit.w = (currProjector.y < projectorArray.y-1) ? overlapUnit.w : 0.0;

	}
	else{
		vec2 projScale = vec2(1.0/projectorRes.x,1.0/projectorRes.y);

		// get corner coordinates
		int projOffset = int(projNr*8);

		vec2 leftBlankUV = texelFetch(cornerCoord,projOffset).rg * projScale.x;
		vec2 leftBlendUV = texelFetch(cornerCoord,projOffset+1).rg * projScale.x;

		vec2 rightBlankUV = texelFetch(cornerCoord,projOffset+2).rg * projScale.x;
		vec2 rightBlendUV = texelFetch(cornerCoord,projOffset+3).rg * projScale.x;

		vec2 topBlankUV = texelFetch(cornerCoord,projOffset+4).rg * projScale.y;
		vec2 topBlendUV = texelFetch(cornerCoord,projOffset+5).rg * projScale.y;

		vec2 bottomBlankUV = texelFetch(cornerCoord,projOffset+6).rg * projScale.y;
		vec2 bottomBlendUV = texelFetch(cornerCoord,projOffset+7).rg * projScale.y;

		// get blankout

		float leftBlank = mix(leftBlankUV.x,leftBlankUV.y,projXY.y);
		float rightBlank = mix(rightBlankUV.x,rightBlankUV.y,projXY.y);
		float topBlank = mix(topBlankUV.x,topBlankUV.y,projXY.x);
		float bottomBlank = mix(bottomBlankUV.x,bottomBlankUV.y,projXY.x);

	 	projBlankout = vec4(leftBlank,rightBlank,bottomBlank,topBlank);

	 	// get overlap

		overlapUnit.x = mix(leftBlendUV.x,leftBlendUV.y,projXY.y);
		overlapUnit.y = mix(rightBlendUV.x,rightBlendUV.y,projXY.y);
		overlapUnit.z = mix(bottomBlendUV.x,bottomBlendUV.y,projXY.x);
		overlapUnit.w = mix(topBlendUV.x,topBlendUV.y,projXY.x);

	}

	// corners is bl br tl tr
	vec4 corners = vec4(1.0);
	float cornerMult = 1.0;
	if (projectorArray.x > 1 && projectorArray.y > 1){
		if (currProjector.x > 0){
			if (currProjector.y > 0){
				corners.x = cornerMult;
			}
			if (currProjector.y < projectorArray.y){
				corners.z = cornerMult;
			}
		}
		if (currProjector.x < projectorArray.x){
			if (currProjector.y > 0){
				corners.y = cornerMult;
			}
			if (currProjector.y < projectorArray.y){
				corners.w = cornerMult;
			}	
		}
	} 

	vec4 image = perProjectorOffset(currProjector, outputRes, xy, projXY);

	// convert to hsv
	vec3 hsv = rgb2hsv(image.rgb);
	// get adjust values
	vec4 adjustRes = uTD2DInfos[2].res;
	vec3 adjustR = texture(sTD2DInputs[2], vec2((projNr*3)*adjustRes.x+adjustRes.x/2,0.5)).rgb;
	vec3 adjustG = texture(sTD2DInputs[2], vec2((projNr*3+1)*adjustRes.x+adjustRes.x/2,0.5)).rgb;
	vec3 adjustB = texture(sTD2DInputs[2], vec2((projNr*3+2)*adjustRes.x+adjustRes.x/2,0.5)).rgb;

	vec3 rAdjusted = vec3(hsv.r+adjustR.r,hsv.g+adjustR.g,hsv.b+adjustR.b);
	vec3 gAdjusted = vec3(hsv.r+adjustG.r,hsv.g+adjustG.g,hsv.b+adjustG.b);
	vec3 bAdjusted = vec3(hsv.r+adjustB.r,hsv.g+adjustB.g,hsv.b+adjustB.b);

	// convert to rgb
	image.rgb = vec3(hsv2rgb(rAdjusted).r,hsv2rgb(gAdjusted).g,hsv2rgb(bAdjusted).b);

	vec4 color = (solidEdgeEnable == 1.0) ?
				drawSolidEdges(overlapUnit, projBlankout, solidEdgeColor, projXY, image)
			:	drawSmoothEdges(overlapUnit, projBlankout, projXY, projNr, image, corners);


	//main blankout
	vec4 blankoutUnit = vec4(blankout.xy*outputRes.x,blankout.zw*outputRes.y);
	vec4 blank = vec4(0.0);
	color = (blankoutUnit.x > xy.x) ? blank : color;
	color = (1-blankoutUnit.y < xy.x) ? blank : color;
	color = (blankoutUnit.z > xy.y) ? blank : color;
	color = (1-blankoutUnit.w < xy.y) ? blank : color;

	fragColor = color;
}
